mapper.select:
SELECT b.id AS id, b.user_id AS userId, u.nickname AS nickname, u.phone AS phone, b.reason AS reason, b.operator AS operator, b.status AS status, DATE_FORMAT(b.created_date, '%Y-%m-%d %H:%i:%s') AS createdDate FROM member_blacklist b LEFT JOIN user_info u ON b.user_id = u.userId
ORDER BY b.created_date DESC
LIMIT #{offset}, #{limit}
